#include <iostream>
#include <iterator>
using namespace std;

int main() {
  int numbers[] = {1, 2, 3, 4, 5, 6};

  cout << "Total elements: " << sizeof(numbers) / sizeof(numbers[0]) << endl;
  cout << "Using std::size: " << std::size(numbers) << endl;

  for (size_t i = 0; i < std::size(numbers); i++) {
    cout << numbers[i] << " ";
  }
  return 0;
}
